   1	import * as React from 'react';
   2	import { Button, ButtonVariant, ExpandableSection, Modal, ModalVariant, Tab, Tabs } from '@patternfly/react-core';
   3	import { WorkloadOverview } from '../../types/ServiceInfo';
   4	import * as API from '../../services/Api';
   5	import * as AlertUtils from '../../utils/AlertUtils';
   6	import { RequestRouting } from './RequestRouting';
   7	import { K8sRequestRouting } from './K8sRequestRouting';
   8	import { TrafficShifting, WorkloadWeight } from './TrafficShifting';
   9	import {
  10	  TrafficPolicy,
  11	  ConsistentHashType,
  12	  TrafficPolicyState,
  13	  UNSET
  14	} from '../../components/IstioWizards/TrafficPolicy';
  15	import { ROUND_ROBIN } from './TrafficPolicy';
  16	import { FaultInjection, FaultInjectionRoute } from './FaultInjection';
  17	import { Rule } from './RequestRouting/Rules';
  18	import { K8sRule } from './K8sRequestRouting/K8sRules';
  19	import {
  20	  buildIstioConfig,
  21	  fqdnServiceName,
  22	  getInitConnectionPool,
  23	  getInitFaultInjectionRoute,
  24	  getInitGateway,
  25	  getInitHosts,
  26	  getInitK8sGateway,
  27	  getInitK8sHosts,
  28	  getInitLoadBalancer,
  29	  getInitOutlierDetection,
  30	  getInitPeerAuthentication,
  31	  getInitRules,
  32	  getInitK8sRules,
  33	  getInitTimeoutRetryRoute,
  34	  getInitTlsMode,
  35	  getInitWeights,
  36	  hasGateway,
  37	  hasK8sGateway,
  38	  ServiceWizardProps,
  39	  ServiceWizardState,
  40	  WIZARD_FAULT_INJECTION,
  41	  WIZARD_K8S_REQUEST_ROUTING,
  42	  WIZARD_K8S_GRPC_REQUEST_ROUTING,
  43	  WIZARD_REQUEST_ROUTING,
  44	  WIZARD_REQUEST_TIMEOUTS,
  45	  WIZARD_TCP_TRAFFIC_SHIFTING,
  46	  WIZARD_TITLES,
  47	  WIZARD_TRAFFIC_SHIFTING,
  48	  WizardPreviews,
  49	  getInitK8sGRPCRules
  50	} from './WizardActions';
  51	import { MessageType } from '../../types/MessageCenter';
  52	import { GatewaySelector, GatewaySelectorState } from './GatewaySelector';
  53	import { K8sGatewaySelector, K8sGatewaySelectorState } from './K8sGatewaySelector';
  54	import { VirtualServiceHosts } from './VirtualServiceHosts';
  55	import { K8sRouteHosts } from './K8sRouteHosts';
  56	import { K8sGRPCRouteHosts } from './K8sGRPCRouteHosts';
  57	import { HTTP, GRPC } from './K8sRequestRouting/K8sMatchBuilder';
  58	import {
  59	  DestinationRule,
  60	  Gateway,
  61	  K8sGateway,
  62	  K8sGRPCRoute,
  63	  K8sHTTPRoute,
  64	  PeerAuthentication,
  65	  PeerAuthenticationMutualTLSMode,
  66	  VirtualService
  67	} from '../../types/IstioObjects';
  68	import { kialiStyle } from 'styles/StyleUtils';
  69	import { RequestTimeouts, TimeoutRetryRoute } from './RequestTimeouts';
  70	import { CircuitBreaker, CircuitBreakerState } from './CircuitBreaker';
  71	import _ from 'lodash';
  72	import { ConfigPreviewItem, IstioConfigPreview } from 'components/IstioConfigPreview/IstioConfigPreview';
  73	import { KialiIcon } from '../../config/KialiIcon';
  74	import { ApiResponse } from 'types/Api';
  75	import { t } from 'utils/I18nUtils';
  76	import { dicTypeToGVK, gvkType } from '../../types/IstioConfigList';
  77	import { getGVKTypeString } from '../../utils/IstioConfigUtils';
  78	import { serverConfig } from '../../config';
  79	
  80	const emptyServiceWizardState = (fqdnServiceName: string): ServiceWizardState => {
  81	  return {
  82	    showWizard: false,
  83	    showAdvanced: false,
  84	    showPreview: false,
  85	    confirmationModal: false,
  86	    previews: undefined,
  87	    advancedTabKey: 0,
  88	    workloads: [],
  89	    rules: [],
  90	    k8sRules: [],
  91	    faultInjectionRoute: {
  92	      workloads: [],
  93	      delayed: false,
  94	      delay: {
  95	        percentage: {
  96	          value: 100
  97	        },
  98	        fixedDelay: '5s'
  99	      },
 100	      isValidDelay: true,
 101	      aborted: false,
 102	      abort: {
 103	        percentage: {
 104	          value: 100
 105	        },
 106	        httpStatus: 503
 107	      },
 108	      isValidAbort: true
 109	    },
 110	    timeoutRetryRoute: {
 111	      workloads: [],
 112	      isTimeout: false,
 113	      timeout: '2s',
 114	      isValidTimeout: true,
 115	      isRetry: false,
 116	      retries: {
 117	        attempts: 3,
 118	        perTryTimeout: '2s',
 119	        retryOn: 'gateway-error,connect-failure,refused-stream'
 120	      },
 121	      isValidRetry: true
 122	    },
 123	    valid: {
 124	      mainWizard: true,
 125	      vsHosts: true,
 126	      k8sRouteHosts: true,
 127	      tls: true,
 128	      lb: true,
 129	      gateway: true,
 130	      cp: true,
 131	      od: true
 132	    },
 133	    advancedOptionsValid: true,
 134	    vsHosts: [fqdnServiceName],
 135	    k8sRouteHosts: [fqdnServiceName],
 136	    trafficPolicy: {
 137	      tlsModified: false,
 138	      mtlsMode: UNSET,
 139	      clientCertificate: '',
 140	      privateKey: '',
 141	      caCertificates: '',
 142	      addLoadBalancer: false,
 143	      simpleLB: false,
 144	      consistentHashType: ConsistentHashType.HTTP_HEADER_NAME,
 145	      loadBalancer: {
 146	        simple: ROUND_ROBIN
 147	      },
 148	      peerAuthnSelector: {
 149	        addPeerAuthentication: false,
 150	        addPeerAuthnModified: false,
 151	        mode: PeerAuthenticationMutualTLSMode.UNSET
 152	      },
 153	      addConnectionPool: false,
 154	      connectionPool: {},
 155	      addOutlierDetection: false,
 156	      outlierDetection: {}
 157	    },
 158	    gateway: undefined,
 159	    k8sGateway: undefined
 160	  };
 161	};
 162	
 163	const advancedOptionsStyle = kialiStyle({
 164	  marginTop: '0.5rem'
 165	});
 166	
 167	export class ServiceWizard extends React.Component<ServiceWizardProps, ServiceWizardState> {
 168	  constructor(props: ServiceWizardProps) {
 169	    super(props);
 170	    this.state = emptyServiceWizardState(fqdnServiceName(props.serviceName, props.namespace));
 171	  }
 172	
 173	  componentDidUpdate(prevProps: ServiceWizardProps): void {
 174	    if (prevProps.show !== this.props.show || !this.compareWorkloads(prevProps.workloads, this.props.workloads)) {
 175	      let isMainWizardValid: boolean;
 176	
 177	      switch (this.props.type) {
 178	        // By default the rule of Weighted routing should be valid
 179	        case WIZARD_TRAFFIC_SHIFTING:
 180	          isMainWizardValid = true;
 181	          break;
 182	        case WIZARD_K8S_REQUEST_ROUTING:
 183	          isMainWizardValid = false;
 184	          break;
 185	        case WIZARD_K8S_GRPC_REQUEST_ROUTING:
 186	          isMainWizardValid = false;
 187	          break;
 188	        // By default no rules is a no valid scenario
 189	        case WIZARD_REQUEST_ROUTING:
 190	          isMainWizardValid = false;
 191	          break;
 192	        case WIZARD_FAULT_INJECTION:
 193	        case WIZARD_REQUEST_TIMEOUTS:
 194	        default:
 195	          isMainWizardValid = true;
 196	          break;
 197	      }
 198	
 199	      const initVsHosts = getInitHosts(this.props.virtualServices);
 200	      const initK8sRoutes = getInitK8sHosts(this.props.k8sHTTPRoutes, this.props.k8sGRPCRoutes);
 201	
 202	      const [initMtlsMode, initClientCertificate, initPrivateKey, initCaCertificates] = getInitTlsMode(
 203	        this.props.destinationRules
 204	      );
 205	
 206	      const initLoadBalancer = getInitLoadBalancer(this.props.destinationRules);
 207	      let initConsistentHashType = ConsistentHashType.HTTP_HEADER_NAME;
 208	
 209	      if (initLoadBalancer && initLoadBalancer.consistentHash) {
 210	        if (initLoadBalancer.consistentHash.httpHeaderName) {
 211	          initConsistentHashType = ConsistentHashType.HTTP_HEADER_NAME;
 212	        } else if (initLoadBalancer.consistentHash.httpCookie) {
 213	          initConsistentHashType = ConsistentHashType.HTTP_COOKIE;
 214	        } else if (initLoadBalancer.consistentHash.useSourceIp) {
 215	          initConsistentHashType = ConsistentHashType.USE_SOURCE_IP;
 216	        }
 217	      }
 218	
 219	      const initPeerAuthentication = getInitPeerAuthentication(
 220	        this.props.destinationRules,
 221	        this.props.peerAuthentications
 222	      );
 223	
 224	      const initConnetionPool = getInitConnectionPool(this.props.destinationRules);
 225	      const initOutlierDetection = getInitOutlierDetection(this.props.destinationRules);
 226	
 227	      const trafficPolicy: TrafficPolicyState = {
 228	        tlsModified: initMtlsMode !== '',
 229	        mtlsMode: initMtlsMode !== '' ? initMtlsMode : UNSET,
 230	        clientCertificate: initClientCertificate,
 231	        privateKey: initPrivateKey,
 232	        caCertificates: initCaCertificates,
 233	        addLoadBalancer: initLoadBalancer !== undefined,
 234	        simpleLB: initLoadBalancer !== undefined && initLoadBalancer.simple !== undefined,
 235	        consistentHashType: initConsistentHashType,
 236	        loadBalancer: initLoadBalancer
 237	          ? initLoadBalancer
 238	          : {
 239	              simple: ROUND_ROBIN
 240	            },
 241	        peerAuthnSelector: {
 242	          addPeerAuthentication: initPeerAuthentication !== undefined,
 243	          addPeerAuthnModified: false,
 244	          mode: initPeerAuthentication || PeerAuthenticationMutualTLSMode.UNSET
 245	        },
 246	        addConnectionPool: initConnetionPool ? true : false,
 247	        connectionPool: initConnetionPool
 248	          ? initConnetionPool
 249	          : {
 250	              tcp: {
 251	                maxConnections: 1
 252	              },
 253	              http: {
 254	                http1MaxPendingRequests: 1
 255	              }
 256	            },
 257	        addOutlierDetection: initOutlierDetection ? true : false,
 258	        outlierDetection: initOutlierDetection
 259	          ? initOutlierDetection
 260	          : {
 261	              consecutiveErrors: 1
 262	            }
 263	      };
 264	
 265	      const gateway: GatewaySelectorState = {
 266	        addGateway: false,
 267	        gwHosts: '',
 268	        gwHostsValid: false,
 269	        newGateway: false,
 270	        selectedGateway: '',
 271	        gatewayClass: '',
 272	        addMesh: false,
 273	        port: 80,
 274	        isOpen: false
 275	      };
 276	
 277	      const k8sGateway: K8sGatewaySelectorState = {
 278	        addGateway: false,
 279	        gwHosts: '',
 280	        gwHostsValid: false,
 281	        newGateway: false,
 282	        selectedGateway: '',
 283	        gatewayClass: '',
 284	        addMesh: false,
 285	        port: 80,
 286	        isOpen: false
 287	      };
 288	
 289	      if (hasGateway(this.props.virtualServices)) {
 290	        const [gatewaySelected, isMesh] = getInitGateway(this.props.virtualServices);
 291	        gateway.addGateway = true;
 292	        gateway.selectedGateway = gatewaySelected;
 293	        gateway.addMesh = isMesh;
 294	      }
 295	
 296	      if (hasK8sGateway(this.props.k8sHTTPRoutes, this.props.k8sGRPCRoutes)) {
 297	        const gatewaySelected = getInitK8sGateway(this.props.k8sHTTPRoutes, this.props.k8sGRPCRoutes);
 298	        k8sGateway.addGateway = true;
 299	        k8sGateway.selectedGateway = gatewaySelected;
 300	      }
 301	
 302	      this.setState({
 303	        showWizard: this.props.show,
 304	        showPreview: false,
 305	        workloads: [],
 306	        rules: [],
 307	        k8sRules: [],
 308	        valid: {
 309	          mainWizard: isMainWizardValid,
 310	          vsHosts: true,
 311	          k8sRouteHosts: true,
 312	          tls: true,
 313	          lb: true,
 314	          gateway: true,
 315	          cp: true,
 316	          od: true
 317	        },
 318	        vsHosts:
 319	          initVsHosts.length > 1 || (initVsHosts.length === 1 && initVsHosts[0].length > 0)
 320	            ? initVsHosts
 321	            : [fqdnServiceName(this.props.serviceName, this.props.namespace)],
 322	        k8sRouteHosts:
 323	          initK8sRoutes.length > 1 || (initK8sRoutes.length === 1 && initK8sRoutes[0].length > 0)
 324	            ? initK8sRoutes
 325	            : [fqdnServiceName(this.props.serviceName, this.props.namespace)],
 326	        trafficPolicy: trafficPolicy,
 327	        gateway: gateway,
 328	        k8sGateway: k8sGateway
 329	      });
 330	    }
 331	  }
 332	
 333	  compareWorkloads = (prev: WorkloadOverview[], current: WorkloadOverview[]): boolean => {
 334	    if (prev.length !== current.length) {
 335	      return false;
 336	    }
 337	
 338	    for (let i = 0; i < prev.length; i++) {
 339	      if (!current.some(w => _.isEqual(w, prev[i]))) {
 340	        return false;
 341	      }
 342	    }
 343	
 344	    return true;
 345	  };
 346	
 347	  onClose = (changed: boolean): void => {
 348	    this.setState(emptyServiceWizardState(fqdnServiceName(this.props.serviceName, this.props.namespace)));
 349	    this.props.onClose(changed);
 350	  };
 351	
 352	  onCreateUpdate = (): void => {
 353	    const promises: Promise<ApiResponse<string>>[] = [];
 354	
 355	    switch (this.props.type) {
 356	      case WIZARD_TRAFFIC_SHIFTING:
 357	      case WIZARD_TCP_TRAFFIC_SHIFTING:
 358	      case WIZARD_K8S_REQUEST_ROUTING:
 359	      case WIZARD_K8S_GRPC_REQUEST_ROUTING:
 360	      case WIZARD_REQUEST_ROUTING:
 361	      case WIZARD_FAULT_INJECTION:
 362	      case WIZARD_REQUEST_TIMEOUTS:
 363	        const dr = this.state.previews!.dr;
 364	        const vs = this.state.previews!.vs;
 365	        const gw = this.state.previews!.gw;
 366	        const k8sgateway = this.state.previews!.k8sgateway;
 367	        const k8shttproute = this.state.previews!.k8shttproute;
 368	        const k8sgrpcroute = this.state.previews!.k8sgrpcroute;
 369	        const pa = this.state.previews!.pa;
 370	
 371	        // Gateway is only created when user has explicit selected this option
 372	        if (gw) {
 373	          promises.push(
 374	            API.createIstioConfigDetail(
 375	              this.props.namespace,
 376	              dicTypeToGVK[gvkType.Gateway],
 377	              JSON.stringify(gw),
 378	              this.props.cluster
 379	            )
 380	          );
 381	        }
 382	
 383	        if (k8sgateway) {
 384	          promises.push(
 385	            API.createIstioConfigDetail(
 386	              this.props.namespace,
 387	              dicTypeToGVK[gvkType.K8sGateway],
 388	              JSON.stringify(k8sgateway),
 389	              this.props.cluster
 390	            )
 391	          );
 392	        }
 393	
 394	        if (this.props.update) {
 395	          if (dr) {
 396	            promises.push(
 397	              API.updateIstioConfigDetail(
 398	                this.props.namespace,
 399	                dicTypeToGVK[gvkType.DestinationRule],
 400	                dr.metadata.name,
 401	                JSON.stringify(dr),
 402	                this.props.cluster
 403	              )
 404	            );
 405	          }
 406	
 407	          if (vs) {
 408	            promises.push(
 409	              API.updateIstioConfigDetail(
 410	                this.props.namespace,
 411	                dicTypeToGVK[gvkType.VirtualService],
 412	                vs.metadata.name,
 413	                JSON.stringify(vs),
 414	                this.props.cluster
 415	              )
 416	            );
 417	          }
 418	
 419	          if (k8shttproute) {
 420	            promises.push(
 421	              API.updateIstioConfigDetail(
 422	                this.props.namespace,
 423	                dicTypeToGVK[gvkType.K8sHTTPRoute],
 424	                k8shttproute.metadata.name,
 425	                JSON.stringify(k8shttproute),
 426	                this.props.cluster
 427	              )
 428	            );
 429	          }
 430	
 431	          if (k8sgrpcroute) {
 432	            promises.push(
 433	              API.updateIstioConfigDetail(
 434	                this.props.namespace,
 435	                dicTypeToGVK[gvkType.K8sGRPCRoute],
 436	                k8sgrpcroute.metadata.name,
 437	                JSON.stringify(k8sgrpcroute),
 438	                this.props.cluster
 439	              )
 440	            );
 441	          }
 442	
 443	          if (dr) {
 444	            this.handlePeerAuthnUpdate(pa, dr, promises);
 445	          }
 446	          // Note that Gateways are not updated from the Wizard, only the VS hosts/gateways sections are updated
 447	        } else {
 448	          if (dr) {
 449	            promises.push(
 450	              API.createIstioConfigDetail(
 451	                this.props.namespace,
 452	                dicTypeToGVK[gvkType.DestinationRule],
 453	                JSON.stringify(dr),
 454	                this.props.cluster
 455	              )
 456	            );
 457	          }
 458	
 459	          if (vs) {
 460	            promises.push(
 461	              API.createIstioConfigDetail(
 462	                this.props.namespace,
 463	                dicTypeToGVK[gvkType.VirtualService],
 464	                JSON.stringify(vs),
 465	                this.props.cluster
 466	              )
 467	            );
 468	          }
 469	
 470	          if (k8shttproute) {
 471	            promises.push(
 472	              API.createIstioConfigDetail(
 473	                this.props.namespace,
 474	                dicTypeToGVK[gvkType.K8sHTTPRoute],
 475	                JSON.stringify(k8shttproute),
 476	                this.props.cluster
 477	              )
 478	            );
 479	          }
 480	
 481	          if (k8sgrpcroute) {
 482	            promises.push(
 483	              API.createIstioConfigDetail(
 484	                this.props.namespace,
 485	                dicTypeToGVK[gvkType.K8sGRPCRoute],
 486	                JSON.stringify(k8sgrpcroute),
 487	                this.props.cluster
 488	              )
 489	            );
 490	          }
 491	
 492	          if (pa) {
 493	            promises.push(
 494	              API.createIstioConfigDetail(
 495	                this.props.namespace,
 496	                dicTypeToGVK[gvkType.PeerAuthentication],
 497	                JSON.stringify(pa),
 498	                this.props.cluster
 499	              )
 500	            );
 501	          }
 502	        }
 503	
 504	        break;
 505	      default:
 506	    }
 507	
 508	    // Disable button before promise is completed. Then Wizard is closed.
 509	    this.setState(prevState => {
 510	      prevState.valid.mainWizard = false;
 511	
 512	      return {
 513	        valid: prevState.valid
 514	      };
 515	    });
 516	
 517	    Promise.all(promises)
 518	      .then(results => {
 519	        if (results.length > 0) {
 520	          AlertUtils.add(
 521	            `Istio Config ${this.props.update ? 'updated' : 'created'} for ${this.props.serviceName} service.`,
 522	            'default',
 523	            MessageType.SUCCESS
 524	          );
 525	        }
 526	        this.onClose(true);
 527	      })
 528	      .catch(error => {
 529	        AlertUtils.addError(`Could not ${this.props.update ? 'update' : 'create'} Istio config objects.`, error);
 530	        this.onClose(true);
 531	      });
 532	  };
 533	
 534	  handlePeerAuthnUpdate = (
 535	    pa: PeerAuthentication | undefined,
 536	    dr: DestinationRule,
 537	    promises: Promise<ApiResponse<string>>[]
 538	  ): void => {
 539	    if (pa) {
 540	      if (this.state.trafficPolicy.peerAuthnSelector.addPeerAuthnModified) {
 541	        promises.push(
 542	          API.createIstioConfigDetail(
 543	            this.props.namespace,
 544	            dicTypeToGVK[gvkType.PeerAuthentication],
 545	            JSON.stringify(pa),
 546	            this.props.cluster
 547	          )
 548	        );
 549	      } else {
 550	        promises.push(
 551	          API.updateIstioConfigDetail(
 552	            this.props.namespace,
 553	            dicTypeToGVK[gvkType.PeerAuthentication],
 554	            dr.metadata.name,
 555	            JSON.stringify(pa),
 556	            this.props.cluster
 557	          )
 558	        );
 559	      }
 560	    } else if (this.state.trafficPolicy.peerAuthnSelector.addPeerAuthnModified) {
 561	      promises.push(
 562	        API.deleteIstioConfigDetail(
 563	          this.props.namespace,
 564	          dicTypeToGVK[gvkType.PeerAuthentication],
 565	          dr.metadata.name,
 566	          this.props.cluster
 567	        )
 568	      );
 569	    }
 570	  };
 571	
 572	  onVsHosts = (valid: boolean, vsHosts: string[]): void => {
 573	    this.setState(prevState => {
 574	      prevState.valid.vsHosts = valid;
 575	      if (prevState.gateway && prevState.gateway.addGateway && prevState.gateway.newGateway) {
 576	        prevState.gateway.gwHosts = vsHosts.join(',');
 577	      }
 578	
 579	      // Check if Gateway is valid after a VsHosts check
 580	      if (valid && !prevState.valid.gateway) {
 581	        const hasVsWildcard = vsHosts.some(h => h === '*');
 582	
 583	        if (hasVsWildcard) {
 584	          if (prevState.gateway && !prevState.gateway.addMesh) {
 585	            prevState.valid.gateway = true;
 586	          }
 587	        } else {
 588	          // If no wildcard Gateway should be ok
 589	          prevState.valid.gateway = true;
 590	        }
 591	      }
 592	
 593	      return {
 594	        valid: prevState.valid,
 595	        vsHosts: vsHosts
 596	      };
 597	    });
 598	  };
 599	
 600	  onK8sRouteHosts = (valid: boolean, k8sRouteHosts: string[]): void => {
 601	    this.setState(prevState => {
 602	      prevState.valid.k8sRouteHosts = valid;
 603	      if (prevState.k8sGateway && prevState.k8sGateway.addGateway && prevState.k8sGateway.newGateway) {
 604	        prevState.k8sGateway.gwHosts = k8sRouteHosts.join(',');
 605	      }
 606	
 607	      return {
 608	        valid: prevState.valid,
 609	        k8sRouteHosts: k8sRouteHosts
 610	      };
 611	    });
 612	  };
 613	
 614	  onTrafficPolicy = (valid: boolean, trafficPolicy: TrafficPolicyState): void => {
 615	    this.setState(prevState => {
 616	      // At the moment this callback only updates the valid of the loadbalancer
 617	      // tls is always true, but I maintain it on the structure for consistency
 618	      prevState.valid.tls = valid;
 619	      prevState.valid.lb = valid;
 620	
 621	      return {
 622	        valid: prevState.valid,
 623	        trafficPolicy: trafficPolicy
 624	      };
 625	    });
 626	  };
 627	
 628	  onCircuitBreaker = (circuitBreaker: CircuitBreakerState): void => {
 629	    this.setState(prevState => {
 630	      prevState.valid.cp = circuitBreaker.isValidConnectionPool;
 631	      prevState.valid.od = circuitBreaker.isValidOutlierDetection;
 632	      prevState.trafficPolicy.addConnectionPool = circuitBreaker.addConnectionPool;
 633	      prevState.trafficPolicy.connectionPool = circuitBreaker.connectionPool;
 634	      prevState.trafficPolicy.addOutlierDetection = circuitBreaker.addOutlierDetection;
 635	      prevState.trafficPolicy.outlierDetection = circuitBreaker.outlierDetection;
 636	
 637	      return {
 638	        valid: prevState.valid,
 639	        trafficPolicy: prevState.trafficPolicy
 640	      };
 641	    });
 642	  };
 643	
 644	  onGateway = (valid: boolean, gateway: GatewaySelectorState): void => {
 645	    this.setState(prevState => {
 646	      prevState.valid.gateway = valid;
 647	
 648	      return {
 649	        valid: prevState.valid,
 650	        gateway: gateway,
 651	        vsHosts:
